import { baseApiPath } from '@/constants/config';
import { namespacedSchema } from '@/constants/schemas';
import {
  JSON_MERGE_PATCH_OPTIONS,
  STRATEGIC_MERGE_PATCH_OPTIONS,
} from '@/devworkspaceClient/services/helpers/patchOptions';
import { restParams } from '@/models';
import {
  createAgentPod,
  deleteAgentPod,
  getAgentPodStatus,
  getAgentServiceUrl,
  heartbeatAgentPod,
  watchAndInjectKubeConfig,
} from '@/routes/api/helpers/agentPod';
import {
  CONFIGMAP_NAME,
  DevfileIdParams,
  getCoreV1Api,
  getOrCreateConfigMap,
  parseEntries,
} from '@/routes/api/helpers/devfile';
