const tags = ['Devfile Creator'];

// Cache resolved terminal service URLs so that subsequent requests
// (asset loads, WebSocket upgrades) can reuse them.
const terminalUrlCache = new Map<string, { url: string; timestamp: number }>();
const TERMINAL_URL_CACHE_TTL = 5 * 60 * 1000; // 5 minutes

function getCachedTerminalUrl(namespace: string): string | undefined {
  const entry = terminalUrlCache.get(namespace);
  if (!entry) return undefined;
  if (Date.now() - entry.timestamp > TERMINAL_URL_CACHE_TTL) {
    terminalUrlCache.delete(namespace);
    return undefined;
  }
  return entry.url;
}

function setCachedTerminalUrl(namespace: string, url: string): void {
  terminalUrlCache.set(namespace, { url, timestamp: Date.now() });
}

const namespacedIdSchema = {
  type: 'object',
  required: ['namespace', 'id'],
  properties: {
    namespace: { type: 'string' },
    id: { type: 'string' },
  },
};

const namespacedAgentIdSchema = {
  type: 'object',
  required: ['namespace', 'agentId'],
  properties: {
    namespace: { type: 'string' },
    agentId: { type: 'string' },
  },
};

export function registerDevfileCreatorRoute(instance: FastifyInstance) {
  instance.register(async server => {
    // List all devfiles
    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace`,
      getSchema({ tags, params: namespacedSchema }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        return { devfiles: parseEntries(configMap.data) };
      },
    );

    // Create agent pod + service
    server.post(
      `${baseApiPath}/devfile-creator/namespace/:namespace/agent`,
      getSchema({ tags, params: namespacedSchema }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const body = request.body as {
          agentId: string;
          image: string;
          tag: string;
          memoryLimit: string;
          cpuLimit: string;
          terminalPort: number;
          env: Array<{ name: string; value: string }>;
        };

        const status = await createAgentPod(token, namespace, body.agentId, {
          image: body.image,
          tag: body.tag,
          memoryLimit: body.memoryLimit,
          cpuLimit: body.cpuLimit,
          terminalPort: body.terminalPort,
          env: body.env,
        });

        watchAndInjectKubeConfig(token, namespace, body.agentId);

        if (status.serviceUrl) {
          setCachedTerminalUrl(namespace, status.serviceUrl);
        }

        return status;
      },
    );

    // Get agent pod status
    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace/agent/:agentId`,
      getSchema({ tags, params: namespacedAgentIdSchema }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const { agentId } = request.params as { agentId: string };
        const query = request.query as Record<string, string | undefined>;
        const terminalPort = query.terminalPort ? parseInt(query.terminalPort, 10) : 8080;

        const status = await getAgentPodStatus(token, namespace, agentId, terminalPort);
        if (!status) {
          reply.code(404).send({ message: 'Agent pod not found' });
          return;
        }

        if (status.serviceUrl) {
          setCachedTerminalUrl(namespace, status.serviceUrl);
        }

        return status;
      },
    );

    // Delete agent pod
    server.delete(
      `${baseApiPath}/devfile-creator/namespace/:namespace/agent/:agentId`,
      getSchema({ tags, params: namespacedAgentIdSchema }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const { agentId } = request.params as { agentId: string };

        await deleteAgentPod(token, namespace, agentId);
        terminalUrlCache.delete(namespace);
        reply.code(204).send();
      },
    );

    // Agent heartbeat — updates TTL annotation to prevent auto-cleanup
    server.post(
      `${baseApiPath}/devfile-creator/namespace/:namespace/agent/:agentId/heartbeat`,
      getSchema({ tags, params: namespacedAgentIdSchema }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const token = getToken(request);
        const { agentId } = request.params as { agentId: string };

        await heartbeatAgentPod(token, namespace, agentId);
        return { ok: true };
      },
    );

    // Check if agent terminal is reachable (health check)
    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace/agent-terminal-url`,
      getSchema({ tags, params: namespacedSchema }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const query = request.query as Record<string, string | undefined>;
        const agentId = query.agentId || 'anthropic/claude-code';
        const terminalPort = query.terminalPort ? parseInt(query.terminalPort, 10) : 8080;

        const serviceUrl = getAgentServiceUrl(namespace, agentId, terminalPort);
        setCachedTerminalUrl(namespace, serviceUrl);

        await new Promise<void>((resolve, reject) => {
          const url = new URL('/', serviceUrl);
          const req = http.get(
            { hostname: url.hostname, port: url.port, path: '/', timeout: 2000 },
            res => {
              res.resume();
              if (res.statusCode && res.statusCode < 500) {
                resolve();
              } else {
                reject(new Error('Terminal server not ready'));
              }
            },
          );
          req.on('error', reject);
          req.on('timeout', () => {
            req.destroy();
            reject(new Error('Terminal server timeout'));
          });
        });

        return { url: serviceUrl };
      },
    );

    // WebSocket proxy for ttyd terminal — relays binary frames between the
    // browser iframe and the in-cluster ttyd server.
    // Buffers client messages until the upstream connection is open to avoid
    // dropping RESIZE/auth frames that ttyd needs for PTY initialization.
    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace/t/ws`,
      { websocket: true, schema: { tags } },
      (socket: WebSocket, request: FastifyRequest) => {
        const { namespace } = request.params as restParams.INamespacedParams;
        const cached = getCachedTerminalUrl(namespace);
        if (!cached) {
          socket.close(1011, 'Terminal service URL not found');
          return;
        }

        const queryString = new URL(request.url, 'http://localhost').search;
        const wsUrl = `${cached.replace(/^http/, 'ws')}/ws${queryString}`;
        const upstream = new WebSocket(wsUrl, ['tty']);

        const pendingMessages: Array<{ data: WebSocket.RawData; isBinary: boolean }> = [];

        upstream.on('open', () => {
          logger.info('Terminal WebSocket upstream connected: %s', wsUrl);
          for (const msg of pendingMessages) {
            upstream.send(msg.data, { binary: msg.isBinary });
          }
          pendingMessages.length = 0;
        });

        socket.on('message', (data: WebSocket.RawData, isBinary: boolean) => {
          if (upstream.readyState === WebSocket.OPEN) {
            upstream.send(data, { binary: isBinary });
          } else if (upstream.readyState === WebSocket.CONNECTING) {
            pendingMessages.push({ data, isBinary });
          }
        });

        upstream.on('message', (data: WebSocket.RawData, isBinary: boolean) => {
          if (socket.readyState === WebSocket.OPEN) {
            socket.send(data, { binary: isBinary });
          }
        });

        socket.on('close', () => {
          if (upstream.readyState <= WebSocket.OPEN) upstream.close();
        });
        upstream.on('close', () => {
          if (socket.readyState <= WebSocket.OPEN) socket.close();
        });

        socket.on('error', err => {
          logger.error(err, 'Terminal WebSocket client error');
          upstream.close();
        });
        upstream.on('error', err => {
          logger.error(err, 'Terminal WebSocket upstream error');
          socket.close();
        });
      },
    );

    // HTTP reverse proxy for ttyd — serves HTML, JS, CSS, and other static
    // assets through the dashboard origin so the iframe can load them.
    const terminalProxyHandler = async function (request: FastifyRequest, reply: FastifyReply) {
      const { namespace } = request.params as restParams.INamespacedParams;
      const requestUrl = new URL(request.url, 'http://localhost');
      const agentId = requestUrl.searchParams.get('agentId') || 'anthropic/claude-code';
      const terminalPort = requestUrl.searchParams.get('terminalPort')
        ? parseInt(requestUrl.searchParams.get('terminalPort') as string, 10)
        : 8080;

      let serviceUrl: string;
      const cached = getCachedTerminalUrl(namespace);
      if (cached) {
        serviceUrl = cached;
      } else {
        serviceUrl = getAgentServiceUrl(namespace, agentId, terminalPort);
        setCachedTerminalUrl(namespace, serviceUrl);
      }

      const prefix = `${baseApiPath}/devfile-creator/namespace/${namespace}/t`;
      const subPath = request.url.slice(prefix.length) || '/';

      logger.info(
        'Terminal proxy: %s %s -> %s%s',
        request.method,
        request.url,
        serviceUrl,
        subPath,
      );
      return proxyToTerminal(serviceUrl, subPath, prefix, request, reply);
    };

    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace/t/*`,
      { schema: { tags } },
      terminalProxyHandler,
    );

    // Create new devfile
    server.post(
      `${baseApiPath}/devfile-creator/namespace/:namespace`,
      getSchema({ tags, params: namespacedSchema }),
      async function (request: FastifyRequest) {
        const { namespace } = request.params as restParams.INamespacedParams;
        const body = request.body as { content: string };
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const id = randomUUID();
        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        const data = { ...configMap.data, [id]: body.content };

        await coreV1Api.patchNamespacedConfigMap(
          {
            name: CONFIGMAP_NAME,
            namespace,
            body: { data },
          },
          STRATEGIC_MERGE_PATCH_OPTIONS,
        );

        return { id };
      },
    );

    // Update devfile
    server.put(
      `${baseApiPath}/devfile-creator/namespace/:namespace/:id`,
      getSchema({ tags, params: namespacedIdSchema }),
      async function (request: FastifyRequest) {
        const { namespace, id } = request.params as DevfileIdParams;
        const body = request.body as { content: string };
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        if (!configMap.data?.[id]) {
          throw new Error(`Devfile with id "${id}" not found`);
        }

        const data = { ...configMap.data, [id]: body.content };
        await coreV1Api.patchNamespacedConfigMap(
          {
            name: CONFIGMAP_NAME,
            namespace,
            body: { data },
          },
          STRATEGIC_MERGE_PATCH_OPTIONS,
        );

        return { id };
      },
    );

    // Delete devfile
    server.delete(
      `${baseApiPath}/devfile-creator/namespace/:namespace/:id`,
      getSchema({ tags, params: namespacedIdSchema }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace, id } = request.params as DevfileIdParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        if (configMap.data?.[id]) {
          await coreV1Api.patchNamespacedConfigMap(
            {
              name: CONFIGMAP_NAME,
              namespace,
              body: { data: { [id]: null } },
            },
            JSON_MERGE_PATCH_OPTIONS,
          );
        }

        reply.code(204).send();
      },
    );

    // Raw devfile content (plain YAML, no download headers)
    // Generated by Claude Opus 4.6
    server.get(
      `${baseApiPath}/devfile-creator/namespace/:namespace/:id/raw`,
      getSchema({ tags, params: namespacedIdSchema }),
      async function (request: FastifyRequest, reply: FastifyReply) {
        const { namespace, id } = request.params as DevfileIdParams;
        const token = getToken(request);
        const coreV1Api = getCoreV1Api(token);

        const configMap = await getOrCreateConfigMap(coreV1Api, namespace);
        const content = configMap.data?.[id];
        if (!content) {
          return reply.status(404).send('Devfile not found');
        }

        reply.header('Content-Type', 'text/yaml; charset=utf-8');
        return reply.send(content);
      },
    );
  });
}
